 import java.sql.*;
 import sailpoint.object.Custom;
 import sailpoint.tools.Message;
 import sailpoint.tools.GeneralException;


 Custom custom = context.getObjectByName(Custom.class,"ProvisioningTransaction Get Add Operation Entitlement");
 if( custom == null ){
   throw new GeneralException("The Custom Object with 'ProvisioningTransaction Get Add Operation Entitlement' is not exist");
 }
 String provTransactionId = custom.get("latestProvisoningTransactionID");
 if( provTransactionId == null || provTransactionId.isEmpty() ){
   throw new GeneralException("latestProvisoningTransactionID  key value is null or Empty");
 }

 //name,ExtractValue(attributes, '//AttributeRequest[@op=\"Add\"]/@value') AS EntitlementValue, applicationName, identityName

 String query = "sql:SELECT name,ExtractValue(attributes, '//AttributeRequest[@op=\"Add\"]/@value') AS EntitlementValue FROM identityiq.spt_provisioning_transaction where name > "+provTransactionId+" and attributes LIKE '%op=\"Add\"%' and status='Success'";

 Iterator it = context.search(query, null, null);
 while(it.hasNext()){

   Object[] obj = it.next();
   log.error(obj[0]);
   log.error(obj[1]);
 }



